public function search(Request $request)
{
    $query = Admin::query();

    if ($request->has('name')) {
        $query->where('name', 'like', '%' . $request->name . '%');
    }

    if ($request->has('email')) {
        $query->where('email', 'like', '%' . $request->email . '%');
    }

    $admins = $query->paginate(10);

    return response()->json($admins);
}
```

